import{_ as a,o as t,c as p,j as e,a as o,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const u=JSON.parse('{"title":"血契师","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/学识类/血契师.md","filePath":"4.资源分区/6.技艺及称号/学识类/血契师.md"}'),s={name:"4.资源分区/6.技艺及称号/学识类/血契师.md"};function d(l,r,b,_,i,c){return t(),p("div",null,[...r[0]||(r[0]=[e("h1",{id:"血契师",tabindex:"-1"},[o("血契师 "),e("a",{class:"header-anchor",href:"#血契师","aria-label":'Permalink to "血契师"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),n('<h1 id="血契师-1" tabindex="-1">血契师 <a class="header-anchor" href="#血契师-1" aria-label="Permalink to &quot;血契师&quot;">​</a></h1><p>血契师</p><p>D+500<br> 购买后获得【鲜血律动】与【血液感知】特性<br> 【鲜血律动】<br> 当你理解了血液不仅是生命的载体，更是力量的源泉，流动的血脉便成为了你操控的乐章。每一次心跳，都是一次力量的共鸣；每一滴血珠，都是一个等待释放的秘密。<br> 你开启一个特殊的魔力池：血能池，其关键属性为感知+操控，并且获得一个基础使用方式：一轮一次，消耗2点魔力，在本轮中伤势不会自动恶化。<br> 并且你现在可以使用【感知+学识+血液学+能量爆发】进行施法检定。</p><p>【血液感知】<br> 通过对自身血液的感知和控制，你获得了一种特殊的&quot;血脉感应&quot;。你能够感知到周围感知范围内所有具有血液(或类似循环系统)生物的存在和大致位置，这是一种非线性的感知。这种感应不受光线影响，但可能被特定的屏蔽能力阻断。</p><p>【伤口共鸣】<br> 价格：C+1000<br> 你可以与敌人的伤口建立短暂的&quot;共鸣&quot;。每当你对敌人造成伤害时，你可以立即花费3点魔力以一个自由动作&quot;标记&quot;该敌人。被标记的敌人将在接下来的三轮内与你建立血液共鸣，使你对其进行的后续攻击检定获得感知附加*2点增强加值。对于被你标记的敌人而言，你能通过感知其血液流动状态来获得【真实视觉】，你能够以花招动作切换可建立真实视觉的单位。</p><p>【创伤扩大】</p><p>D+1000<br> 你的攻击造成的伤害将使敌人血流不止。<br> 你的施法攻击额外附带1点不可豁免的流血异常点数。</p><p>【鲜血盗取】</p><p>C+1000<br> 对已经处于流血状态的敌人，你可以尝试&quot;抽取&quot;其血液为己所用。</p><p>你对具有流血异常点数的敌人造成伤害时，你从目标体内抽取部分血液，将等同于目标当前流血异常点数的严重伤害转化为韧性伤害，并回复自己一半数量的生命值（最多计算2点流血异常点数）。</p><p>【血液感知】中的感知升级为强感知。</p><p>【血池召唤】</p><p>B+2000<br> 你可以在地面上创造一片危险的血池。以一个标准动作，消耗4点生命值和10点魔力，选择施法范围内的一点，下轮开始时以目标点所在位置为中心创造一个半径50米的血池。血池持续3轮，进入其中的单位每轮结束时需要进行一次DC为29的强韧豁免，若失败则受到4点不可豁免的流血异常点数，并且处于其中的单位移动速度减半(如同处于C级困难地形)，同时受到B级重伤效果的影响，这是一个B级环境来源的效果。</p><p>【血爆初现】</p><p>B+2000<br> 你开始掌握操控敌人体内血液的可怕能力。对一个处于至少2层流血异常点数的目标，你可以尝试引发其体内的血液发生局部爆发。</p><p>以一个标准动作消耗10点能量进行一次施法攻击，敌人以强韧豁免对抗伤害出目。若成功，可以选择目标的一个非要害部位(如手臂、腿部)，引发该部位的血管突然扩张破裂，造成剧烈疼痛并将其彻底摧毁，这是一个B级创伤来源的肢体残障效果。<br> 目标需要进行一次意志豁免对抗伤害出目，失败则因疼痛在一轮内受到B级创伤来源的震慑效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const f=a(s,[["render",d]]);export{u as __pageData,f as default};
